namespace HaCreator.GUI.InstanceEditor{public partial class MirrorFieldEditor:EditorBase{public MirrorFieldData _mirrorFieldData;public MirrorFieldEditor(MirrorFieldData data){InitializeComponent();_mirrorFieldData=data;checkBox_reflection.IsChecked=data.ReflectionInfo.Reflection;checkBox_alphaTest.IsChecked=data.ReflectionInfo.AlphaTest;gradientSlider.Value=data.ReflectionInfo.Gradient;alphaSlider.Value=data.ReflectionInfo.Alpha;InstanceEditorDialogSupport.SetInt(xOffset,(int)data.Offset.X);InstanceEditorDialogSupport.SetInt(yOffset,(int)data.Offset.Y);comboBox_objectForOverlay.SelectedIndex=0;pathLabel.Text=HaCreatorStateManager.CreateItemDescription(data);UpdateLabels();}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){lock(_mirrorFieldData.Board.ParentControl){_mirrorFieldData.ReflectionInfo.Reflection=checkBox_reflection.IsChecked==true;_mirrorFieldData.ReflectionInfo.AlphaTest=checkBox_alphaTest.IsChecked==true;_mirrorFieldData.ReflectionInfo.Gradient=(ushort)gradientSlider.Value;_mirrorFieldData.ReflectionInfo.Alpha=(ushort)alphaSlider.Value;_mirrorFieldData.Offset=new Microsoft.Xna.Framework.Vector2(InstanceEditorDialogSupport.GetInt(xOffset),(int)InstanceEditorDialogSupport.GetInt(yOffset));_mirrorFieldData.ReflectionInfo.ObjectForOverlay=(comboBox_objectForOverlay.SelectedItem as System.Windows.Controls.ComboBoxItem)?.Content as string;}Close();}private void UpdateLabels(){if(label_gradient==null)return;label_gradient.Text=$"Gradient: {(int)gradientSlider.Value}";label_alphaValue.Text=$"Alpha: {(int)alphaSlider.Value}";}private void Gradient_Changed(object s,RoutedPropertyChangedEventArgs<double> e)=>UpdateLabels();private void Alpha_Changed(object s,RoutedPropertyChangedEventArgs<double> e)=>UpdateLabels();private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventA